#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-03

# tests/hooks/test-run-hook-dispatcher.sh
# Validates run-hook.mjs dispatcher: input normalization, bundle resolution,
# security overrides, and stdin edge cases.
set -euo pipefail

PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)}"
RUN_HOOK="$PROJECT_ROOT/plugins/ork/hooks/bin/run-hook.mjs"

RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[0;33m'
NC='\033[0m'

PASS=0
FAIL=0
SKIP=0

pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo -e "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }
skip() { echo -e "  ${YELLOW}⊘${NC} $1 (skipped)"; SKIP=$((SKIP + 1)); }

# Helper: run run-hook.mjs with stdin and capture stdout/stderr/exit
# Usage: run_hook <hook-name> <stdin-json> [extra-env-vars...]
run_hook() {
  local hook_name="$1"
  local stdin_data="$2"
  shift 2
  local env_args=()
  for arg in "$@"; do env_args+=("$arg"); done

  local tmpout; tmpout=$(mktemp)
  local tmperr; tmperr=$(mktemp)

  local exit_code=0
  env "${env_args[@]}" node "$RUN_HOOK" "$hook_name" \
    < <(printf '%s' "$stdin_data") \
    >"$tmpout" 2>"$tmperr" || exit_code=$?

  LAST_STDOUT=$(cat "$tmpout")
  LAST_STDERR=$(cat "$tmperr")
  LAST_EXIT=$exit_code
  rm -f "$tmpout" "$tmperr"
}

# Helper: extract JSON field from LAST_STDOUT
json_field() {
  python3 -c "import json,sys; print(json.loads(sys.argv[1]).get('$1',''))" "$LAST_STDOUT" 2>/dev/null || echo ""
}

echo "Run-Hook Dispatcher Tests"
echo "========================="

# Pre-check: run-hook.mjs exists
if [[ ! -f "$RUN_HOOK" ]]; then
  fail "run-hook.mjs not found at $RUN_HOOK"
  exit 1
fi
pass "run-hook.mjs exists"

# =============================================================================
echo ""
echo "1. Input Normalization"
echo "----------------------"

# 1a. hook_event_name → hook_event
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"hook_event_name":"PreToolUse","tool_input":{"command":"echo safe"}}' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]] && echo "$LAST_STDOUT" | python3 -c "import json,sys; assert json.load(sys.stdin).get('continue') == True" 2>/dev/null; then
  pass "hook_event_name='PreToolUse' accepted (exit 0, continue:true)"
else
  fail "hook_event_name normalization failed (exit=$LAST_EXIT, stdout=$LAST_STDOUT)"
fi

# 1b. hook_event passes through unchanged
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"hook_event":"PreToolUse","tool_input":{"command":"echo safe"}}' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "hook_event='PreToolUse' passes through (exit 0)"
else
  fail "hook_event passthrough failed (exit=$LAST_EXIT)"
fi

# 1c. toolInput → tool_input (old CC format)
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"toolInput":{"command":"echo legacy"},"hook_event":"PreToolUse"}' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "toolInput normalized to tool_input (exit 0)"
else
  fail "toolInput normalization failed (exit=$LAST_EXIT)"
fi

# 1d. cwd → project_dir (SubagentStart format)
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"cwd":"/tmp/test-project","tool_input":{"command":"ls"},"hook_event":"PreToolUse"}' \
  "CLAUDE_PROJECT_DIR="
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "cwd normalized to project_dir (exit 0)"
else
  fail "cwd→project_dir normalization failed (exit=$LAST_EXIT)"
fi

# 1e. agent_type → tool_input.subagent_type (SubagentStart)
run_hook "subagent-start/context-budget-guard" \
  '{"agent_type":"Explore","agent_id":"abc-123","hook_event":"SubagentStart"}' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "agent_type/agent_id promoted to tool_input (exit 0)"
else
  fail "agent_type promotion failed (exit=$LAST_EXIT)"
fi

# 1f. Garbage project_dir (starts with '{') falls back to '.'
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"project_dir":"{\"leaked\":true}","tool_input":{"command":"echo hi"},"hook_event":"PreToolUse"}' \
  "CLAUDE_PROJECT_DIR="
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "JSON-like project_dir rejected, falls back gracefully (exit 0)"
else
  fail "Garbage project_dir handling failed (exit=$LAST_EXIT)"
fi

# =============================================================================
echo ""
echo "2. Bundle Resolution"
echo "--------------------"

# 2a. All 12 bundle prefixes resolve without crash
BUNDLE_PREFIXES="permission pretool posttool prompt lifecycle stop subagent-start subagent-stop notification setup skill agent"
ALL_RESOLVE=true
for prefix in $BUNDLE_PREFIXES; do
  # Use a fake hook name — just testing bundle resolution, not actual hook logic
  run_hook "${prefix}/test-nonexistent" \
    '{"tool_input":{},"hook_event":"Test"}' \
    "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
  if [[ $LAST_EXIT -ne 0 ]]; then
    fail "Bundle '${prefix}' crashed (exit=$LAST_EXIT, stderr=$LAST_STDERR)"
    ALL_RESOLVE=false
    break
  fi
done
if $ALL_RESOLVE; then
  pass "All 12 bundle prefixes resolve (exit 0, SILENT_OK for missing hooks)"
fi

# 2b. Unknown prefix → SILENT_OK
run_hook "unknown-prefix/some-hook" '{}' "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]] && echo "$LAST_STDOUT" | grep -q '"continue":true'; then
  pass "Unknown bundle prefix returns SILENT_OK"
else
  fail "Unknown prefix didn't return SILENT_OK (exit=$LAST_EXIT, stdout=$LAST_STDOUT)"
fi

# 2c. No hook name → SILENT_OK
LAST_STDOUT=""
LAST_EXIT=999
local_tmpout=$(mktemp)
local_tmperr=$(mktemp)
node "$RUN_HOOK" < /dev/null >"$local_tmpout" 2>"$local_tmperr" || true
LAST_STDOUT=$(cat "$local_tmpout")
LAST_EXIT=$?
rm -f "$local_tmpout" "$local_tmperr"
if echo "$LAST_STDOUT" | grep -q '"continue":true'; then
  pass "No hook name returns SILENT_OK"
else
  fail "No hook name didn't return SILENT_OK (stdout=$LAST_STDOUT)"
fi

# =============================================================================
echo ""
echo "3. Security Hook Override Protection"
echo "------------------------------------"

# 3a. Security hooks cannot be disabled via hook-overrides.json
TEMP_PROJECT=$(mktemp -d)
mkdir -p "$TEMP_PROJECT/.claude"
cat > "$TEMP_PROJECT/.claude/hook-overrides.json" << 'OVERRIDE_EOF'
{
  "disabled": [
    "pretool/bash/dangerous-command-blocker",
    "pretool/bash/compound-command-validator",
    "pretool/write-edit/file-guard",
    "pretool/Write/security-pattern-validator",
    "skill/redact-secrets"
  ]
}
OVERRIDE_EOF

run_hook "pretool/bash/dangerous-command-blocker" \
  "{\"tool_input\":{\"command\":\"echo hello\"},\"hook_event\":\"PreToolUse\",\"project_dir\":\"$TEMP_PROJECT\"}" \
  "CLAUDE_PROJECT_DIR=$TEMP_PROJECT"
if [[ $LAST_EXIT -eq 0 ]] && echo "$LAST_STDERR" | grep -q "cannot disable security hook"; then
  pass "Security hook override rejected with warning"
else
  # Even if no stderr warning, the hook must still run (not silenced)
  if [[ $LAST_EXIT -eq 0 ]] && ! echo "$LAST_STDOUT" | grep -q '"suppressOutput":true'; then
    pass "Security hook still executed despite override attempt"
  else
    fail "Security hook may have been disabled (exit=$LAST_EXIT, stderr=$LAST_STDERR)"
  fi
fi

# 3b. Non-security hook CAN be disabled
run_hook "posttool/telemetry/emit" \
  "{\"tool_input\":{},\"hook_event\":\"PostToolUse\",\"project_dir\":\"$TEMP_PROJECT\"}"
# This is a non-security hook — if overrides had it, it would be disabled
# Since it's not in the disabled list, it should still run normally
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "Non-security hook unaffected by unrelated overrides (exit 0)"
else
  fail "Non-security hook affected by overrides (exit=$LAST_EXIT)"
fi

rm -rf "$TEMP_PROJECT"

# =============================================================================
echo ""
echo "4. Stdin Edge Cases"
echo "-------------------"

# 4a. Empty stdin → hook runs with empty input
run_hook "pretool/bash/dangerous-command-blocker" "" "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "Empty stdin handled gracefully (exit 0)"
else
  fail "Empty stdin caused crash (exit=$LAST_EXIT)"
fi

# 4b. Invalid JSON → graceful error with continue:true
run_hook "pretool/bash/dangerous-command-blocker" \
  'NOT VALID JSON {{{{' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]] && echo "$LAST_STDOUT" | grep -q '"continue":true'; then
  pass "Invalid JSON returns continue:true (no crash)"
else
  fail "Invalid JSON didn't gracefully recover (exit=$LAST_EXIT, stdout=$LAST_STDOUT)"
fi

# 4c. Valid but empty object
run_hook "pretool/bash/dangerous-command-blocker" '{}' "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "Empty JSON object handled (exit 0)"
else
  fail "Empty JSON object caused crash (exit=$LAST_EXIT)"
fi

# 4d. Oversized stdin (>512KB) — produces truncation warning
# Use a temp file to avoid shell ARG_MAX limits on large payloads
if command -v python3 &>/dev/null; then
  LARGE_FILE=$(mktemp)
  python3 -c "import json; open('$LARGE_FILE','w').write(json.dumps({'tool_input':{'command':'echo hi'},'hook_event':'PreToolUse','padding':'x'*600000}))"
  local_tmpout=$(mktemp)
  local_tmperr=$(mktemp)
  local_exit=0
  env "CLAUDE_PROJECT_DIR=$PROJECT_ROOT" node "$RUN_HOOK" "pretool/bash/dangerous-command-blocker" \
    < "$LARGE_FILE" >"$local_tmpout" 2>"$local_tmperr" || local_exit=$?
  LAST_STDOUT=$(cat "$local_tmpout")
  LAST_STDERR=$(cat "$local_tmperr")
  LAST_EXIT=$local_exit
  rm -f "$LARGE_FILE" "$local_tmpout" "$local_tmperr"
  if echo "$LAST_STDERR" | grep -qi "truncat"; then
    pass "Oversized stdin (>512KB) produces truncation warning (exit=$LAST_EXIT)"
  elif [[ $LAST_EXIT -eq 0 ]]; then
    pass "Oversized stdin handled without crash (no truncation warning — payload may fit)"
  else
    fail "Oversized stdin caused crash (exit=$LAST_EXIT, stderr=$LAST_STDERR)"
  fi
else
  skip "Oversized stdin test (python3 not available)"
fi

# =============================================================================
echo ""
echo "5. Input Validation"
echo "-------------------"

# 5a. Array input rejected
run_hook "pretool/bash/dangerous-command-blocker" '[1,2,3]' "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]] && echo "$LAST_STDOUT" | grep -q "validation failed"; then
  pass "Array input rejected with validation error"
else
  # Arrays parse as objects in some paths — just verify no crash
  if [[ $LAST_EXIT -eq 0 ]]; then
    pass "Array input handled gracefully (exit 0)"
  else
    fail "Array input caused crash (exit=$LAST_EXIT)"
  fi
fi

# 5b. Null input → graceful handling
run_hook "pretool/bash/dangerous-command-blocker" 'null' "CLAUDE_PROJECT_DIR=$PROJECT_ROOT"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "Null JSON input handled gracefully (exit 0)"
else
  fail "Null JSON input caused crash (exit=$LAST_EXIT)"
fi

# =============================================================================
echo ""
echo "6. Session ID Validation (SEC-001)"
echo "-----------------------------------"

# 6a. Valid UUID session ID
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"tool_input":{"command":"echo hi"},"hook_event":"PreToolUse"}' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT" "CLAUDE_SESSION_ID=be33e3e1-5918-4057-904d-89997790dd8b"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "UUID session ID accepted (exit 0)"
else
  fail "UUID session ID rejected (exit=$LAST_EXIT)"
fi

# 6b. Smart ID format
run_hook "pretool/bash/dangerous-command-blocker" \
  '{"tool_input":{"command":"echo hi"},"hook_event":"PreToolUse"}' \
  "CLAUDE_PROJECT_DIR=$PROJECT_ROOT" "CLAUDE_SESSION_ID=orchestkit-main-0403-1030-a1b2"
if [[ $LAST_EXIT -eq 0 ]]; then
  pass "Smart session ID accepted (exit 0)"
else
  fail "Smart session ID rejected (exit=$LAST_EXIT)"
fi

# =============================================================================
# Summary
echo ""
echo "================================="
echo "Results: $PASS passed, $FAIL failed, $SKIP skipped"
[[ $FAIL -eq 0 ]] && exit 0 || exit 1
